package jetbrains.mps.build.migration;

/*Generated by MPS */

import jetbrains.mps.tool.builder.WorkerBase;
import jetbrains.mps.tool.common.Script;
import jetbrains.mps.tool.environment.Environment;
import jetbrains.mps.tool.environment.IdeaEnvironment;
import jetbrains.mps.tool.environment.EnvironmentConfig;
import jetbrains.mps.tool.builder.WorkerHelper;
import jetbrains.mps.smodel.MPSModuleRepository;
import java.util.function.Supplier;
import java.util.Collection;
import org.jetbrains.mps.openapi.module.SModule;
import jetbrains.mps.util.IterableUtil;
import java.io.File;
import jetbrains.mps.project.Project;
import com.intellij.openapi.application.ApplicationManager;
import com.intellij.ide.plugins.PluginManagerCore;
import com.intellij.openapi.extensions.PluginId;
import java.lang.reflect.Method;
import com.intellij.openapi.project.ProjectManager;
import com.intellij.openapi.application.ModalityState;

public class MigrationWorker extends WorkerBase {
  private static final String MIGRATION_PLUGIN = "jetbrains.mps.ide.migration.workbench";
  private static final String TASK_EXEC_CLASS = "jetbrains.mps.ide.migration.AntTaskExecutionUtil";

  public MigrationWorker(Script whatToDo) {
    super(whatToDo);
  }

  @Override
  protected Environment createEnvironment() {
    IdeaEnvironment environment = new IdeaEnvironment(createEnvironmentConfig(myWhatToDo));
    environment.init();
    return environment;
  }

  @Override
  protected EnvironmentConfig createEnvironmentConfig(Script whatToDo) {
    return super.createEnvironmentConfig(whatToDo).withMigrationPlugin();
  }

  @Override
  public void work() {
    // todo the following line is needed until we introduce layered migration
    // FIXME why do I care to make these modules?
    WorkerHelper compileReloadHelper = new WorkerHelper(myEnvironment.getPlatform());
    final MPSModuleRepository repo = myEnvironment.getPlatform().findComponent(MPSModuleRepository.class);

    compileReloadHelper.makeAndReload(repo, new Supplier<Collection<SModule>>() {
      public Collection<SModule> get() {
        return IterableUtil.asCollection(repo.getModules());
      }
    }, myJavaCompilerOptions);

    for (File file : myWhatToDo.getMPSProjectFiles()) {
      final Project[] container = new Project[1];
      container[0] = myEnvironment.openProject(file);
      final Project project = container[0];
      info("Loaded project " + project);
      myEnvironment.flushAllEvents();

      compileReloadHelper.makeAndReload(project.getRepository(), new Supplier<Collection<SModule>>() {
        public Collection<SModule> get() {
          return (Collection<SModule>) project.getProjectModulesWithGenerators();
        }
      }, myJavaCompilerOptions);

      myEnvironment.flushAllEvents();

      ApplicationManager.getApplication().invokeAndWait(new Runnable() {
        public void run() {
          try {
            // XXX instead of explicit IDEA's PluginManager, we could use CL of "j.m.migration.component" MPS module to load desired class
            // MPS would resort to proper plugin CL to perform the task.
            Class<?> euClass = PluginManagerCore.getPlugin(PluginId.getId(MIGRATION_PLUGIN)).getPluginClassLoader().loadClass(TASK_EXEC_CLASS);
            Method method = euClass.getMethod("migrate", Project.class, Boolean.TYPE);
            method.invoke(null, project, myWhatToDo.getHaltOnPrecheckFailure());
            com.intellij.openapi.project.Project[] projects = ProjectManager.getInstance().getOpenProjects();
            assert projects.length == 1 : "more than one project opened: " + projects.length;
            // fixme we should close via environment
            ProjectManager.getInstance().closeAndDispose(projects[0]);
          } catch (Exception e) {
            throw new RuntimeException("Exception during migration", e);
          }
        }
      }, ModalityState.defaultModalityState());

      project.dispose();
      myEnvironment.flushAllEvents();
    }
  }

  public static void main(String[] args) {
    MigrationWorker mpsWorker = new MigrationWorker(Script.fromDumpInFile(new File(args[0])));
    mpsWorker.workFromMain();
  }
}
